 26	import { getReferenceForModel } from '../pipelines-overview/utils';
 27	import './DetailsPage.scss';
 28	
 29	export type Action = {
 30	  type?: string;
 31	  key: string;
 32	  label: React.ReactNode;
 33	  hidden?: boolean;
 34	  disabledTooltip?: React.ReactNode;
 35	} & Omit<DropdownItemProps, 'label'>;
 36	
 37	type DetailsPageProps = {
 38	  obj?: K8sResourceKind;
 39	  title: React.ReactNode;
 40	  headTitle?: string;
 41	  preComponent?: React.ReactNode;
 42	  children?: React.ReactNode;
 43	  footer?: React.ReactNode;
 44	  description?: React.ReactNode;
 45	  breadcrumbs?: ({ name: string; path: string } | React.ReactElement)[];
 46	  actions?: Action[];
 47	  baseURL?: string;
 48	  onTabSelect?: (selectedTabKey: string) => void;
 49	  model?: K8sModel;
 50	  pages?: NavPage[];
 51	};
 52	
 53	const DetailsPage: React.FC<React.PropsWithChildren<DetailsPageProps>> = ({
 54	  obj,
 55	  title,
 56	  preComponent = null,
 57	  footer,
 58	  description,
 59	  breadcrumbs,
 60	  actions = [],
 61	  model,
 62	  pages,
 63	}) => {
 64	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 65	  const [isOpen, setIsOpen] = React.useState(false);
 66	  const toggleIsOpen = React.useCallback(() => setIsOpen((v) => !v), []);
 67	  const setClosed = React.useCallback(() => setIsOpen(false), []);
 68	
 69	  const dropdownItems = React.useMemo(
 70	    () =>
 71	      actions?.reduce((acc, action) => {
 72	        const { key, label, isDisabled, component, ...props } = action;
 73	        if (action.hidden) {
 74	          return acc;
 75	        }
 76	
 77	        acc.push(
 78	          <DropdownItem
 79	            key={key}
 80	            data-test={key}
 81	            isDisabled={isDisabled}
 82	            component={!isDisabled ? component : 'a'}
 83	            {...props}
 84	          >
 85	            {label}
 86	          </DropdownItem>,
 87	        );
 88	
 89	        return acc;
 90	      }, [] as React.ReactNode[]),
 91	    [actions],
 92	  );
 93	
 94	  const renderTitle = () => {
 95	    return (
 96	      <div className="co-m-pane__name co-resource-item co-m-pane__heading">
 97	        {model && (
 98	          <ResourceIcon
 99	            kind={getReferenceForModel(model)}
100	            className="co-m-resource-icon--lg"
101	          />
102	        )}
103	        <span
104	          data-test-id="resource-title"
105	          className="co-resource-item__resource-name"
106	        >
107	          {title}
108	        </span>
109	      </div>
110	    );
111	  };
112	
113	  return (
114	    <PageGroup data-test="details" className="app-details">
115	      <PageSection type="breadcrumb" className="co-m-nav-title--detail">
116	        {breadcrumbs && (
117	          <BreadCrumbs
118	            data-test="details__breadcrumbs"
119	            breadcrumbs={breadcrumbs}
120	          />
121	        )}
122	        <Flex style={{ paddingTop: 'var(--pf-t--global--spacer--300)' }}>
123	          <FlexItem>
124	            <TextContent>
125	              {renderTitle()}
126	              {description && <Text component="p">{description}</Text>}
127	            </TextContent>
128	          </FlexItem>
129	          {actions?.length ? (
130	            <FlexItem align={{ default: 'alignRight' }}>
131	              <Dropdown
132	                data-test="details__actions"
133	                onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
134	                onSelect={setClosed}
135	                toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
136	                  <MenuToggle
137	                    ref={toggleRef}
138	                    onClick={toggleIsOpen}
139	                    isExpanded={isOpen}
140	                  >
141	                    {t('Actions')}
142	                  </MenuToggle>
143	                )}
144	                isOpen={isOpen}
145	              >
146	                <DropdownList className="action-menu-dropdown">
147	                  {dropdownItems}
148	                </DropdownList>
149	              </Dropdown>
150	            </FlexItem>
151	          ) : null}
152	        </Flex>
153	      </PageSection>
154	      {preComponent}
155	      <HorizontalNav pages={pages} resource={obj} />
156	      {footer && (
157	        <PageSection variant={PageSectionVariants.light} isFilled={false}>
158	          {footer}
159	        </PageSection>
160	      )}
161	    </PageGroup>
162	  );
163	};
164	
165	export default DetailsPage;

